<!DOCTYPE html><html><head><meta charset="utf-8">
<link href="https://fonts.googleapis.com/css2?family=Exo+2:wght@300;400;500&display=swap" rel="stylesheet">
<style>
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
html,body{background:transparent}
#ait{--c:#8fe9ff;max-width:520px;margin:12px auto 0;font-family:'Exo 2',sans-serif}
#ait .think{font-size:13px;font-style:italic;color:#9ccada;letter-spacing:.3px;display:flex;align-items:center;gap:9px;
  opacity:0;animation:aitIn .7s ease .05s forwards}
#ait .ln{flex:0 0 26px;height:1px;background:linear-gradient(90deg,var(--c),transparent);transform-origin:left;animation:aitLn 3.2s ease-in-out infinite}
#ait .out{flex:1;min-width:0}
#ait .cue{flex:0 0 auto;display:inline-flex;gap:3px;margin-left:2px}
#ait .cue b{width:4px;height:4px;border-radius:50%;background:var(--c);box-shadow:0 0 7px var(--c);animation:aitBlip 1.4s ease-in-out infinite}
#ait .cue b:nth-child(2){animation-delay:.22s}#ait .cue b:nth-child(3){animation-delay:.44s}
@keyframes aitIn{to{opacity:1}}
@keyframes aitLn{0%,100%{opacity:.4;transform:scaleX(.7)}50%{opacity:1;transform:scaleX(1)}}
@keyframes aitBlip{0%,100%{opacity:.25;transform:translateY(0)}50%{opacity:1;transform:translateY(-2px)}}
</style></head>
<body>
<span id="hx" style="display:none">$1</span><span id="tx" style="display:none">$2</span>
<div id="ait"><div class="think"><span class="ln"></span><span class="out" id="out"></span><span class="cue"><b></b><b></b><b></b></span></div></div>
<script>
(function(){
  function txt(id){var e=document.getElementById(id);return e?(e.textContent||'').replace(/^\s+/,'').replace(/\s+$/,''):'';}
  var hex=txt('hx'), body=txt('tx');
  document.getElementById('out').textContent=body;
  var h=hex.replace(/[^#0-9a-fA-F]/g,'');
  if(h&&h.charAt(0)!=='#')h='#'+h;
  if(/^#([0-9a-fA-F]{3}|[0-9a-fA-F]{6}|[0-9a-fA-F]{8})$/.test(h))document.getElementById('ait').style.setProperty('--c',h);
})();
</script>
</body></html>
